// Silver medal raw (declared first so _heroMedailleB64 can extract from it)
const HERO_MEDAILLE_SILVER_XML_RAW = `<svg width="209" height="207" viewBox="0 0 209 207" fill="none" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
<rect width="209" height="207" fill="url(#pattern0_77_537)"/>
<defs>
<pattern id="pattern0_77_536" patternContentUnits="objectBoundingBox" width="1" height="1">
<use xlink:href="#image0_77_536" transform="matrix(0.00276243 0 0 0.00278912 0 -0.000647236)"/>
</pattern>
<pattern id="pattern0_77_537" patternContentUnits="objectBoundingBox" width="1" height="1">
<use xlink:href="#image0_77_537" transform="matrix(0.00277778 0 0 0.0027912 0 -0.00101986)"/>
</pattern>
<image id="image0_77_537" width="360" height="359" preserveAspectRatio="none" xlink:href="data:image/png;base64,"/>
</defs>
</svg>`;

// Public silver export (kept for backward compat)
export const HERO_MEDAILLE_SILVER_XML = HERO_MEDAILLE_SILVER_XML_RAW;

// Extract shared base64 PNG from silver (gold uses the same image)
const _b64 = (() => {
  const m = HERO_MEDAILLE_SILVER_XML_RAW.match(/xlink:href="data:image\/png;base64,([^"]+)"/);
  return m ? m[1] : '';
})();

export const HERO_MEDAILLE_GOLD_XML = HERO_MEDAILLE_SILVER_XML_RAW; // same image

// ── Direct PNG data URI (use with <Image> instead of SvgXml to avoid web issues) ──
export const HERO_MEDAILLE_URI = `data:image/png;base64,${_b64}`;
